import React, { createContext, useContext, useState, useEffect } from 'react';
import { useChat } from './ChatContext';

const WalletContext = createContext();

export const useWallet = () => {
  const context = useContext(WalletContext);
  if (!context) {
    throw new Error('useWallet must be used within a WalletProvider');
  }
  return context;
};

export const WalletProvider = ({ children }) => {
  const [account, setAccount] = useState('');
  const [chainId, setChainId] = useState('');
  const [isConnected, setIsConnected] = useState(false);
  const [error, setError] = useState('');

  const [userProfile, setUserProfile] = useState({
    displayName: '',
    bio: '',
    avatar: '',
    location: '',
    website: '',
    twitter: ''
  });

  const [ownedNFTs] = useState([
    {
      id: '1',
      name: 'DeChat Genesis',
      collection: 'DeChat Official',
      tokenId: '001',
      image: 'https://via.placeholder.com/150/3b82f6/ffffff?text=NFT1'
    },
    {
      id: '2',
      name: 'Crypto Punk #1234',
      collection: 'CryptoPunks',
      tokenId: '1234',
      image: 'https://via.placeholder.com/150/ef4444/ffffff?text=NFT2'
    }
  ]);

  const connectWallet = async () => {
    setError('');

    if (typeof window.ethereum === 'undefined') {
      setError('MetaMask not detected. Please install MetaMask to continue.');
      return;
    }

    try {
      const accounts = await window.ethereum.request({
        method: 'eth_requestAccounts'
      });

      const currentChainId = await window.ethereum.request({
        method: 'eth_chainId'
      });

      if (accounts.length > 0) {
        setAccount(accounts[0]);
        setChainId(currentChainId);
        setIsConnected(true);
      }
    } catch (err) {
      if (err.code === 4001) {
        setError('Connection rejected. Please approve the connection request.');
      } else {
        setError(err.message || 'Failed to connect wallet');
      }
    }
  };

  const disconnectWallet = () => {
    setAccount('');
    setChainId('');
    setIsConnected(false);
    setError('');
  };

  const updateProfile = (profileData) => {
    setUserProfile(prev => ({ ...prev, ...profileData }));
  };

  useEffect(() => {
    const checkConnection = async () => {
      if (typeof window.ethereum === 'undefined') return;

      try {
        const accounts = await window.ethereum.request({
          method: 'eth_accounts'
        });

        const currentChainId = await window.ethereum.request({
          method: 'eth_chainId'
        });

        if (accounts.length > 0) {
          setAccount(accounts[0]);
          setChainId(currentChainId);
          setIsConnected(true);
        }
      } catch (err) {
        console.error('Failed to check connection:', err);
      }
    };

    checkConnection();
  }, []);

  useEffect(() => {
    if (typeof window.ethereum === 'undefined') return;

    const handleAccountsChanged = (accounts) => {
      if (accounts.length > 0) {
        setAccount(accounts[0]);
        setIsConnected(true);
        setError('');
      } else {
        disconnectWallet();
      }
    };

    const handleChainChanged = (newChainId) => {
      setChainId(newChainId);
      window.location.reload();
    };

    window.ethereum.on('accountsChanged', handleAccountsChanged);
    window.ethereum.on('chainChanged', handleChainChanged);

    return () => {
      if (window.ethereum.removeListener) {
        window.ethereum.removeListener('accountsChanged', handleAccountsChanged);
        window.ethereum.removeListener('chainChanged', handleChainChanged);
      }
    };
  }, []);

  const value = {
    account,
    walletAddress: account,
    chainId,
    isConnected,
    error,
    ownedNFTs,
    userProfile,
    connectWallet,
    disconnectWallet,
    updateProfile
  };

  return (
    <WalletContext.Provider value={value}>
      {children}
    </WalletContext.Provider>
  );
};
